values
('additional-maths:4-1-inequalities-in-two-variables:mcq:8ad648c5', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "You test \\( (0,0) \\) in \\( x + y \\le 4 \\) and obtain \\( 0 \\le 4 \\). Which side satisfies the inequality?", "options": ["The side containing the origin", "The side not containing the origin", "Neither side", "You cannot tell without another point"]}'::jsonb, '{"answer": 0, "explain": "\\( 0 \\le 4 \\) is true, so the origin''s half-plane is the one that satisfies \\( x + y \\le 4 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:a6290d8d', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "Under the OCR exam convention, which region do you shade?", "options": ["The region that is NOT required", "The feasible region itself", "Both regions", "Only the boundary lines"]}'::jsonb, '{"answer": 0, "explain": "You shade the unwanted region, leaving the feasible region clear and easy to read."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:7afbca12', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "Which pair of conditions expresses non-negativity for a real quantity of items?", "options": ["\\( x \\ge 0 \\) and \\( y \\ge 0 \\)", "\\( x > 0 \\) and \\( y > 0 \\)", "\\( x \\le 0 \\) and \\( y \\le 0 \\)", "\\( x = 0 \\) and \\( y = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "You cannot make a negative number of items, so \\( x \\ge 0 \\) and \\( y \\ge 0 \\) — zero is allowed."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:93155e82', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "What is the boundary line of the inequality \\( x + 2y \\le 11 \\)?", "options": ["\\( x + 2y = 11 \\)", "\\( x + 2y < 11 \\)", "\\( x + 2y = 0 \\)", "\\( 2x + y = 11 \\)"]}'::jsonb, '{"answer": 0, "explain": "Replace the inequality sign with equals: the boundary is \\( x + 2y = 11 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:04a32126', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "The boundary \\( 2x + y = 6 \\) crosses the axes at which two points?", "options": ["\\( (3,\\ 0) \\) and \\( (0,\\ 6) \\)", "\\( (6,\\ 0) \\) and \\( (0,\\ 3) \\)", "\\( (2,\\ 0) \\) and \\( (0,\\ 1) \\)", "\\( (6,\\ 0) \\) and \\( (0,\\ 6) \\)"]}'::jsonb, '{"answer": 0, "explain": "Put \\( y = 0 \\Rightarrow 2x = 6 \\Rightarrow x = 3 \\); put \\( x = 0 \\Rightarrow y = 6 \\). Intercepts \\( (3,0) \\) and \\( (0,6) \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:50a8f231', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "The feasible region for a set of inequalities is:", "options": ["The region satisfying every inequality at once (left clear)", "The largest shaded region", "The area under the topmost line", "The region satisfying at least one inequality"]}'::jsonb, '{"answer": 0, "explain": "The feasible region satisfies ALL the constraints simultaneously; on the exam it is the clear, unshaded region."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:996ad97a', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "For \\( y \\ge 2x \\) the boundary passes through the origin. Which is a sensible test point?", "options": ["\\( (1,\\ 0) \\)", "\\( (0,\\ 0) \\)", "\\( (0.5,\\ 1) \\) on the line", "The origin is always best"]}'::jsonb, '{"answer": 0, "explain": "\\( (0,0) \\) lies ON the line, so it cannot decide a side. Use an off-line point such as \\( (1,0) \\): \\( 0 \\ge 2 \\) is false, so \\( (1,0) \\) is on the unwanted side."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:mcq:f7acef9b', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'mcq', 'mcq', 1, '{"question": "A half-plane is best described as:", "options": ["All the points on one side of a boundary line (with the line if the sign is \\( \\le / \\ge \\))", "A line segment", "The area of a triangle", "Half of the coordinate grid, split by the y-axis"]}'::jsonb, '{"answer": 0, "explain": "An inequality in two variables defines a half-plane: everything on one side of its boundary line."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:6fcccf4b', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "The boundary line for \\( y \\le 2x + 3 \\) should be drawn solid."}'::jsonb, '{"answer": true, "explain": "\\( \\le \\) includes equality, so points on the line are part of the region — the boundary is solid."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:5bf3558b', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "For the strict inequality \\( y > x \\), the boundary line is drawn dashed."}'::jsonb, '{"answer": true, "explain": "Strict signs \\( < \\) and \\( > \\) exclude the line, so it is dashed."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:fa8a2702', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "Under the OCR convention you shade the feasible region itself."}'::jsonb, '{"answer": false, "explain": "You shade the region that is NOT required; the feasible region is left clear and unshaded."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:139ef9cc', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "Testing the point \\( (0,0) \\) is a quick way to decide which side of a line to shade."}'::jsonb, '{"answer": true, "explain": "Provided the line does not pass through the origin, substituting \\( (0,0) \\) instantly tells you which side satisfies the inequality."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:754c8448', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "''At least 30'' is written as \\( \\le 30 \\)."}'::jsonb, '{"answer": false, "explain": "''At least 30'' means 30 or more, i.e. \\( \\ge 30 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:aaccfdb1', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "If the boundary line passes through the origin, you should not use \\( (0,0) \\) as your test point."}'::jsonb, '{"answer": true, "explain": "A point on the line cannot decide a side — pick an off-line point such as \\( (1,0) \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:3e5e8dce', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "The conditions \\( x \\ge 0 \\) and \\( y \\ge 0 \\) restrict a real-world region to the first quadrant."}'::jsonb, '{"answer": true, "explain": "Both coordinates non-negative means the region lies in the first quadrant (including the axes)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tf:a6f33725', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tf', 'tf', 1, '{"question": "The point \\( (0,0) \\) satisfies \\( 24x + 28y \\le 400 \\)."}'::jsonb, '{"answer": true, "explain": "\\( 24(0) + 28(0) = 0 \\le 400 \\) is true, so the origin lies in the wanted half-plane."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:b198882a', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "What does a linear inequality in two variables look like on a grid?", "reading": "<p>An equation such as \\( y = x + 1 \\) is a single <strong>line</strong>. An <strong>inequality</strong> such as \\( y \\ge x + 1 \\) is a whole <strong>region</strong> — a <strong>half-plane</strong>: every point on one side of the line, together with the line itself.</p>\n            <ul>\n              <li>The line itself is called the <strong>boundary</strong>. You find it by replacing the inequality sign with an equals sign (here \\( y = x + 1 \\)).</li>\n              <li>The boundary splits the grid into two halves. One half satisfies the inequality; the other does not.</li>\n              <li>A point either <strong>satisfies</strong> the inequality (its coordinates make the statement true) or it does not. For \\( y \\ge x + 1 \\), the point \\( (0, 4) \\) works because \\( 4 \\ge 1 \\), but \\( (4, 0) \\) fails because \\( 0 \\ge 5 \\) is false.</li>\n            </ul>\n            <p>The whole of Linear Programming (Group 4) is built on this idea: describe a situation with several inequalities, then find the region where they are all true at once.</p>", "question": "Which point satisfies \\( y \\ge x + 1 \\)?", "options": ["\\( (1,\\ 5) \\)", "\\( (5,\\ 1) \\)", "\\( (3,\\ 0) \\)", "\\( (4,\\ 2) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (1,5) \\): \\( 5 \\ge 1 + 1 = 2 \\) is true. \\( (5,1) \\) gives \\( 1 \\ge 6 \\), false; \\( (4,2) \\) gives \\( 2 \\ge 5 \\), false."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:8c9e4408', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "How do you draw the boundary line — solid or dashed?", "reading": "<p>Draw the boundary as an ordinary straight line, then decide its <strong>style</strong> from the inequality sign:</p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\le \\) or \\( \\ge \\): the line <strong>is</strong> part of the region, so draw it <strong>solid</strong>.</td></tr>\n              <tr><td>2. \\( < \\) or \\( > \\) (strict): the line is <strong>not</strong> part of the region, so draw it <strong>dashed</strong>.</td></tr>\n            </table>\n            <p>To plot the boundary quickly, use its intercepts. For \\( x + 2y = 11 \\): put \\( x = 0 \\) to get \\( y = 5.5 \\), and put \\( y = 0 \\) to get \\( x = 11 \\). Join \\( (0,\\ 5.5) \\) and \\( (11,\\ 0) \\) with a ruler.</p>\n            <p><strong>Worked example.</strong> Boundary of \\( 24x + 28y \\le 400 \\): the sign is \\( \\le \\), so the line \\( 24x + 28y = 400 \\) is <strong>solid</strong>. Intercepts: \\( x = 0 \\Rightarrow y = \\frac{400}{28} \\approx 14.3 \\); \\( y = 0 \\Rightarrow x = \\frac{400}{24} \\approx 16.7 \\).</p>", "question": "How should the boundary of \\( y > 2x \\) be drawn?", "options": ["Dashed, because the inequality is strict", "Solid, because it is a straight line", "Dashed, because it passes through the origin", "Solid, because \\( > \\) includes equality"]}'::jsonb, '{"answer": 0, "explain": "\\( > \\) is strict, so points on the line are excluded — the boundary is dashed. Only \\( \\le \\) and \\( \\ge \\) give a solid line."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:6620665b', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "Which side of the line do you shade? Test a point.", "reading": "<p>Once the boundary is drawn, one side satisfies the inequality and the other does not. The fastest way to tell them apart is to <strong>test a point</strong> that is clearly on one side.</p>\n            <table class=\"worked\">\n              <tr><td>1. Pick an easy test point not on the line — the <strong>origin \\( (0,\\ 0) \\)</strong> is ideal.</td></tr>\n              <tr><td>2. Substitute it into the inequality.</td></tr>\n              <tr><td>3. If the statement is <strong>true</strong>, the origin''s side is the side that satisfies the inequality. If it is <strong>false</strong>, the other side does.</td></tr>\n            </table>\n            <p><strong>Worked example — \\( x + y \\le 4 \\).</strong> Test \\( (0, 0) \\): \\( 0 + 0 = 0 \\le 4 \\) is <strong>true</strong>, so the region satisfying the inequality is the side <em>containing</em> the origin (below-left of the line).</p>\n            <p><strong>Warning:</strong> if the boundary passes through the origin (for example \\( y \\ge 2x \\)), \\( (0,0) \\) sits <em>on</em> the line and tells you nothing — choose a different test point such as \\( (1, 0) \\).</p>", "question": "You test \\( (0,0) \\) in \\( 3x + y \\le 6 \\) and get \\( 0 \\le 6 \\). What does this tell you?", "options": ["The origin''s side satisfies the inequality", "The origin''s side fails the inequality", "The boundary must be dashed", "Nothing — the origin is on the line"]}'::jsonb, '{"answer": 0, "explain": "\\( 0 \\le 6 \\) is true, so the half-plane containing the origin is the one that satisfies \\( 3x + y \\le 6 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:98678430', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "The OCR exam convention: shade the region you do NOT want", "reading": "<p>This is the single most important habit for the 6993 exam. When you must show a region defined by several inequalities, OCR asks you to <strong>shade the region that is NOT required</strong> — you shade everything that fails. The <strong>feasible region</strong> (the part satisfying every inequality) is then left <strong>clear and unshaded</strong>.</p>\n            <ul>\n              <li>Why? With three or four overlapping inequalities, shading each <em>wanted</em> side would cover the answer in a mess of overlapping shading. Shading the <em>unwanted</em> sides instead leaves a single clean white region — easy to read and to work with.</li>\n              <li>So for each inequality: draw the boundary, work out the wanted side, then <strong>shade the other side</strong>.</li>\n              <li>Always <strong>label the clear region</strong> (e.g. write \"R\") so the examiner knows which region is your answer.</li>\n            </ul>\n            <p>Below, \\( x + y \\le 4 \\) is shown the exam way: the unwanted half-plane (where \\( x + y > 4 \\)) is shaded, leaving the wanted region clear.</p>\n            <svg viewBox=\"0 0 300 240\" width=\"100%\" style=\"max-width:340px;height:auto;display:block;margin:12px auto\" role=\"img\" aria-label=\"Grid showing the line x plus y equals 4 as a solid line, with the region above the line shaded as not wanted and the region below left clear\">\n              <rect x=\"40\" y=\"20\" width=\"220\" height=\"180\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1\" stroke-opacity=\"0.5\"/>\n              <g stroke=\"currentColor\" stroke-width=\"0.6\" stroke-opacity=\"0.2\">\n                <line x1=\"84\" y1=\"20\" x2=\"84\" y2=\"200\"/><line x1=\"128\" y1=\"20\" x2=\"128\" y2=\"200\"/><line x1=\"172\" y1=\"20\" x2=\"172\" y2=\"200\"/><line x1=\"216\" y1=\"20\" x2=\"216\" y2=\"200\"/>\n                <line x1=\"40\" y1=\"164\" x2=\"260\" y2=\"164\"/><line x1=\"40\" y1=\"128\" x2=\"260\" y2=\"128\"/><line x1=\"40\" y1=\"92\" x2=\"260\" y2=\"92\"/><line x1=\"40\" y1=\"56\" x2=\"260\" y2=\"56\"/>\n              </g>\n              <polygon points=\"40,56 216,200 260,200 260,20 40,20\" fill=\"currentColor\" fill-opacity=\"0.13\"/>\n              <line x1=\"40\" y1=\"200\" x2=\"260\" y2=\"200\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"40\" y1=\"20\" x2=\"40\" y2=\"200\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"40\" y1=\"56\" x2=\"216\" y2=\"200\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <g font-size=\"10\" fill=\"currentColor\" text-anchor=\"middle\">\n                <text x=\"40\" y=\"214\">0</text><text x=\"128\" y=\"214\">2</text><text x=\"216\" y=\"214\">4</text>\n                <text x=\"150\" y=\"50\">not wanted (shaded)</text><text x=\"95\" y=\"175\">R (clear)</text>\n                <text x=\"180\" y=\"120\">x + y = 4</text>\n              </g>\n            </svg>", "question": "Under the OCR convention, which part of the diagram is your final answer?", "options": ["The clear (unshaded) region", "The shaded region", "The boundary line only", "Both regions together"]}'::jsonb, '{"answer": 0, "explain": "You shade what is NOT required; the feasible region is the clear, unshaded part — label it R so it is obvious."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:78cbb7bb', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "How do you combine inequalities to leave a feasible region?", "reading": "<p>With several inequalities you draw <em>every</em> boundary on the same grid and shade each unwanted side. The region left clear after all the shading is the <strong>feasible region</strong> — it satisfies them all at once.</p>\n            <p><strong>Worked example.</strong> Show the region satisfying \\( x \\ge 1 \\), \\( y \\ge 1 \\) and \\( x + y \\le 5 \\).</p>\n            <table class=\"worked\">\n              <tr><td>1. \\( x \\ge 1 \\): solid vertical line \\( x = 1 \\); wanted side is to the right, so shade to the <em>left</em>.</td></tr>\n              <tr><td>2. \\( y \\ge 1 \\): solid horizontal line \\( y = 1 \\); wanted side is above, so shade <em>below</em>.</td></tr>\n              <tr><td>3. \\( x + y \\le 5 \\): solid line through \\( (5,0) \\) and \\( (0,5) \\); test \\( (0,0) \\Rightarrow 0 \\le 5 \\) true, so shade <em>above</em> the line.</td></tr>\n            </table>\n            <p>What is left clear is the triangle with vertices \\( (1,1),\\ (1,4),\\ (4,1) \\) — the feasible region \\( R \\).</p>\n            <svg viewBox=\"0 0 320 250\" width=\"100%\" style=\"max-width:360px;height:auto;display:block;margin:12px auto\" role=\"img\" aria-label=\"Grid with lines x equals 1, y equals 1 and x plus y equals 5; the three unwanted half-planes are shaded, leaving a clear triangle with vertices 1,1 and 1,4 and 4,1\">\n              <rect x=\"40\" y=\"18\" width=\"240\" height=\"192\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1\" stroke-opacity=\"0.5\"/>\n              <g stroke=\"currentColor\" stroke-width=\"0.6\" stroke-opacity=\"0.2\">\n                <line x1=\"80\" y1=\"18\" x2=\"80\" y2=\"210\"/><line x1=\"120\" y1=\"18\" x2=\"120\" y2=\"210\"/><line x1=\"160\" y1=\"18\" x2=\"160\" y2=\"210\"/><line x1=\"200\" y1=\"18\" x2=\"200\" y2=\"210\"/><line x1=\"240\" y1=\"18\" x2=\"240\" y2=\"210\"/>\n                <line x1=\"40\" y1=\"178\" x2=\"280\" y2=\"178\"/><line x1=\"40\" y1=\"146\" x2=\"280\" y2=\"146\"/><line x1=\"40\" y1=\"114\" x2=\"280\" y2=\"114\"/><line x1=\"40\" y1=\"82\" x2=\"280\" y2=\"82\"/><line x1=\"40\" y1=\"50\" x2=\"280\" y2=\"50\"/>\n              </g>\n              <polygon points=\"40,210 80,210 80,18 40,18\" fill=\"currentColor\" fill-opacity=\"0.12\"/>\n              <polygon points=\"40,210 280,210 280,178 40,178\" fill=\"currentColor\" fill-opacity=\"0.12\"/>\n              <polygon points=\"40,50 240,210 280,210 280,18 40,18\" fill=\"currentColor\" fill-opacity=\"0.12\"/>\n              <line x1=\"40\" y1=\"210\" x2=\"280\" y2=\"210\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"40\" y1=\"18\" x2=\"40\" y2=\"210\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"80\" y1=\"210\" x2=\"80\" y2=\"18\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <line x1=\"40\" y1=\"178\" x2=\"280\" y2=\"178\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <line x1=\"40\" y1=\"50\" x2=\"240\" y2=\"210\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <polygon points=\"80,178 80,82 200,178\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <g font-size=\"10\" fill=\"currentColor\" text-anchor=\"middle\">\n                <text x=\"40\" y=\"224\">0</text><text x=\"80\" y=\"224\">1</text><text x=\"160\" y=\"224\">3</text><text x=\"240\" y=\"224\">5</text>\n                <text x=\"120\" y=\"165\">R</text>\n              </g>\n            </svg>", "question": "In the combined region above, which point lies inside the feasible region \\( R \\)?", "options": ["\\( (2,\\ 2) \\)", "\\( (0,\\ 0) \\)", "\\( (4,\\ 4) \\)", "\\( (1,\\ 0) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (2,2) \\): \\( x \\ge 1 \\) ✓, \\( y \\ge 1 \\) ✓, \\( x + y = 4 \\le 5 \\) ✓. \\( (0,0) \\) fails \\( x \\ge 1 \\); \\( (4,4) \\) fails \\( x+y \\le 5 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:learn:afde5a15', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'learn', 'mcq', 1, '{"readingTitle": "How do you turn a real situation into inequalities? (CG6)", "reading": "<p>Exam questions usually describe a real situation in words and expect you to <strong>formulate</strong> the constraints as inequalities. Watch the language carefully — the wrong sign loses the mark.</p>\n            <ul>\n              <li>\"<strong>at least</strong> 5\", \"a minimum of 5\", \"5 or more\" \\( \\Rightarrow \\ge 5 \\).</li>\n              <li>\"<strong>no more than</strong> 400\", \"at most 400\", \"cannot exceed 400\" \\( \\Rightarrow \\le 400 \\).</li>\n              <li>\"<strong>more than</strong> 5\" \\( \\Rightarrow > 5 \\); \"<strong>fewer than</strong> 5\" \\( \\Rightarrow < 5 \\) (strict — dashed boundary).</li>\n              <li><strong>Non-negativity:</strong> you cannot make a negative number of chairs or spend negative hours, so almost every real problem also needs \\( x \\ge 0 \\) and \\( y \\ge 0 \\). These keep the region in the first quadrant.</li>\n            </ul>\n            <p><strong>Worked example.</strong> A workshop makes \\( x \\) tables and \\( y \\) chairs. A table needs 24 minutes and a chair 28 minutes of machine time, and there are at most 400 minutes available. As machine time is limited: \\[ 24x + 28y \\le 400. \\] With non-negativity, the full model is \\( 24x + 28y \\le 400,\\ x \\ge 0,\\ y \\ge 0 \\).</p>", "question": "A shop must stock ''at least 30'' of an item, \\( n \\). Which inequality is correct?", "options": ["\\( n \\ge 30 \\)", "\\( n \\le 30 \\)", "\\( n < 30 \\)", "\\( n > 30 \\)"]}'::jsonb, '{"answer": 0, "explain": "''At least 30'' means 30 or more, so \\( n \\ge 30 \\). A common error is to write \\( < \\) or \\( \\le \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:misc:45c9c248', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''The factory must make at least 5 chairs'' \\( \\Rightarrow x < 5 \\).</p><p><strong>✅ The correct idea:</strong> ''At least 5'' means 5 or more, so \\( x \\ge 5 \\). A weak answer uses \\( < \\) (the opposite direction, and strict); a strong answer writes \\( x \\ge 5 \\) — greater than <em>or equal to</em>.</p>", "question": "''At least 5 chairs'' becomes:", "options": ["\\( x \\ge 5 \\)", "\\( x < 5 \\)", "\\( x \\le 5 \\)", "\\( x > 5 \\)"]}'::jsonb, '{"answer": 0, "explain": "''At least'' = ''or more'' = \\( \\ge \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:misc:ff987dc0', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Shading the feasible region so the answer is covered in pencil.</p><p><strong>✅ The correct idea:</strong> OCR asks you to shade the region that is NOT required. A weak answer shades the wanted region (and hides it under overlapping shading); a strong answer shades every unwanted side and labels the clear region R.</p>", "question": "Which region should be left clear (unshaded)?", "options": ["The feasible region", "The unwanted region", "The boundary lines", "The first quadrant"]}'::jsonb, '{"answer": 0, "explain": "Shade the unwanted region; the feasible region stays clear."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:misc:7007c475', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Drawing a solid line for \\( y < 2x + 1 \\).</p><p><strong>✅ The correct idea:</strong> \\( < \\) is strict, so the boundary is excluded and must be dashed. A weak answer always draws solid lines; a strong answer matches the line style to the sign — solid only for \\( \\le \\) / \\( \\ge \\).</p>", "question": "The boundary of \\( y < 2x + 1 \\) is drawn:", "options": ["Dashed", "Solid", "As a curve", "Not at all"]}'::jsonb, '{"answer": 0, "explain": "Strict \\( < \\) means the line is not included — draw it dashed."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:misc:a42499ac', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Deciding the shaded side by guessing, without testing a point.</p><p><strong>✅ The correct idea:</strong> A weak answer shades whichever side ''looks right''; a strong answer substitutes a test point such as \\( (0,0) \\) and lets the true/false result decide the side every time.</p>", "question": "The reliable way to choose the correct side is to:", "options": ["Test a point in the inequality", "Always shade above the line", "Always shade to the right", "Shade the smaller region"]}'::jsonb, '{"answer": 0, "explain": "Substituting a test point removes all guesswork."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:misc:73a96242', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Forgetting the non-negativity constraints in a real-world problem.</p><p><strong>✅ The correct idea:</strong> A weak answer gives only the resource constraints; a strong answer remembers that a real quantity cannot be negative and adds \\( x \\ge 0,\\ y \\ge 0 \\), keeping the region in the first quadrant.</p>", "question": "A real ''number of items'' problem almost always also needs:", "options": ["\\( x \\ge 0 \\) and \\( y \\ge 0 \\)", "\\( x \\le 0 \\) and \\( y \\le 0 \\)", "no extra conditions", "\\( x = y \\)"]}'::jsonb, '{"answer": 0, "explain": "Quantities cannot be negative, so non-negativity is added."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tips:f1048ab9', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tips', 'mcq', 1, '{"readingTitle": "tip — Draw + shade: the 4-mark feature checklist", "reading": "<p>The \"shade the region\" question is worth about 4 marks — one for <strong>each boundary line drawn correctly by its intercepts</strong>, plus a mark for the <strong>shading</strong> (which follows-through from your lines).</p>\n          <p><strong>0 marks:</strong> lines drawn roughly, no clear region, or the wanted region shaded over.</p>\n          <p><strong>Partial:</strong> the three lines drawn correctly by their intercepts (a mark each) but the shading left out or on the wrong sides.</p>\n          <p><strong>Full marks:</strong> each boundary line accurate through its intercept points, every unwanted half-plane shaded, and the feasible region left clear and labelled R. The shading mark is awarded ''follow-through'' on <em>your</em> lines, so correct shading of slightly wrong lines still scores.</p>", "question": "In a 4-mark ''draw and shade'' question, the shading mark is awarded:", "options": ["Follow-through on your own lines, for shading the unwanted region", "Only if every line is perfect", "For shading the feasible region", "For drawing dashed lines"]}'::jsonb, '{"answer": 0, "explain": "Shading is marked ft on your lines, and it is the NOT-required region that must be shaded."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tips:ccc244c7', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''At least'' / ''no more than'' — get the symbol right", "reading": "<p>Formulating a constraint is a 1-mark step where the wrong sign scores nothing.</p>\n          <p><strong>0 marks:</strong> \"at least 2000 units of the drug\" written as \\( 2000x + 1000y \\le 5000 \\) (wrong direction).</p>\n          <p><strong>Full marks:</strong> \"at least\" \\( \\Rightarrow \\ge \\), so \\( 2000x + 1000y \\ge 5000 \\); \"no more than\" \\( \\Rightarrow \\le \\). Any equivalent form (e.g. dividing through) scores ''oe''.</p>", "question": "''The mixture must contain no more than 19 units'' becomes:", "options": ["\\( \\ldots \\le 19 \\)", "\\( \\ldots \\ge 19 \\)", "\\( \\ldots > 19 \\)", "\\( \\ldots = 19 \\)"]}'::jsonb, '{"answer": 0, "explain": "''No more than'' means at most, i.e. \\( \\le 19 \\)."}'::jsonb),
('additional-maths:4-1-inequalities-in-two-variables:tips:f1a0bd4f', 'additional-maths', 'additional-maths:4-1-inequalities-in-two-variables', '4.1 Inequalities in Two Variables', 'tips', 'mcq', 1, '{"readingTitle": "tip — Leave the answer clear — label R", "reading": "<p>The examiner must be able to see which region is your answer.</p>\n          <p><strong>0 marks lost habits:</strong> shading the wanted region, or leaving no label so it is unclear which clear patch is meant.</p>\n          <p><strong>Full marks habit:</strong> shade every unwanted half-plane, leave the feasible region white, and write <strong>R</strong> inside it. If you make a mistake, use the spare grid provided at the back of the booklet and cross out the first attempt.</p>", "question": "Why write ''R'' inside the clear region?", "options": ["So the examiner knows which region is your answer", "It earns a bonus mark", "It is required to shade", "To mark the origin"]}'::jsonb, '{"answer": 0, "explain": "Labelling the feasible region makes your answer unambiguous."}'::jsonb),
